(function () {
  function Html2PdfLite() {
    this.options = {};
    this.source = null;
  }

  Html2PdfLite.prototype.set = function (options) {
    this.options = options || {};
    return this;
  };

  Html2PdfLite.prototype.from = function (source) {
    this.source = source;
    return this;
  };

  Html2PdfLite.prototype.save = function () {
    const title = this.options.filename || "irodori-vocabulary.pdf";
    const previousTitle = document.title;
    document.title = title.replace(/\.pdf$/i, "");
    window.setTimeout(function () {
      window.print();
      document.title = previousTitle;
    }, 80);
    return Promise.resolve();
  };

  window.html2pdf = function () {
    return new Html2PdfLite();
  };
})();
